def fix_file\(file_path, imports_list\):
    """修复单个文件的导入"""
    if not os.path.exists\(file_path\):
        print\(f"  ✗ 文件不存在: {file_path}"\)
        return False

    with open\(file_path, 'r', encoding='utf-8'\) as f:
        content = f.read\(\)

    # 检查是否已经有package声明
    if 'package ' not in content:
        print\(f"  ✗ 无package声明: {file_path}"\)
        return False

    # 找到package声明后的位置
    package_end = content.find\(';', 0, 200\)
    if package_end == -1:
        print\(f"  ✗ package格式错误: {file_path}"\)
        return False

    insert_pos = content.find\('\\n', package_end\)
    if insert_pos == -1:
        insert_pos = package_end + 1

    # 添加缺失的导入
    for imp in imports_list:
        if imp not in content:
            # 在插入位置添加导入
            content = content[:insert_pos] + '\\n' + imp + content[insert_pos:]
            insert_pos += len\(imp\) + 1

    with open\(file_path, 'w', encoding='utf-8'\) as f:
        f.write\(content\)

    return True

# 应用所有修复
